import os, re, glob

new_script = ''''''    <script>
    async function submitToWebPrime\(e\) {
        e.preventDefault\(\);
        var form = document.getElementById\(''contactForm''\);
        var btn = form.querySelector\(''button[type=""submit""]''\);
        var originalText = btn.textContent;

        if \(form._gotcha && form._gotcha.value\) return false;

        btn.textContent = ''Envoi en cours...'';
        btn.disabled = true;

        try {
            var formData = new FormData\(form\);
            var response = await fetch\(''https://webprime.app/webhook/contact/a0dbffb8afffbd140c7c09cb7d2c09e30a8e36bb44f78f4fcd0f5e49af523630'', {
                method: ''POST'',
                body: formData
            }\);

            if \(response.ok\) {
                window.location.href = ''https://cordiste-59.com/'';
            } else {
                alert\(''Erreur. Veuillez reessayer.''\);
                btn.textContent = originalText;
                btn.disabled = false;
            }
        } catch \(error\) {
            alert\(''Erreur de connexion. Veuillez reessayer.''\);
            btn.textContent = originalText;
            btn.disabled = false;
        }
        return false;
    }
    </script>''''''

pattern = r''<script>\\s*function validateForm\\\(\\\)[\\s\\S]*?</script>''

files = glob.glob\(''cordiste-*.html''\) + glob.glob\(''entreprise-*.html''\) + glob.glob\(''maintenance-*.html''\) + glob.glob\(''nettoyage-*.html''\) + glob.glob\(''peinture-*.html''\) + glob.glob\(''pose-*.html''\) + glob.glob\(''ravalement-*.html''\) + glob.glob\(''installation-*.html''\) + glob.glob\(''urgence-*.html''\) + glob.glob\(''devis-*.html''\)

for file in files:
    try:
        with open\(file, ''r'', encoding=''utf-8''\) as f:
            content = f.read\(\)
        new_content = re.sub\(pattern, new_script, content\)
        with open\(file, ''w'', encoding=''utf-8''\) as f:
            f.write\(new_content\)
        print\(f''OK: {file}''\)
    except Exception as e:
        print\(f''ERR {file}: {e}''\)
")

